function sumNested(arr) {
  let total = 0;
  for (let i = 0, n = arr.length; i < n; i++) {
    const inner = arr[i];
    for (let j = 0, m = inner.length; j < m; j++) {
      total += inner[j];
    }
  }
  return total;
}

